#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X; scanf("%lld", &X);
        if (X % 5 != 0) {
            printf("-1\n");
        } else {
            long long ans = X/10 + (X%10)/5;
            printf("%lld\n", ans);
        }
    }
    return 0;
}

